INSERT INTO formations (id_formation, titre, description, duree, prix, categorie, date_debut, places_disponibles, created_at, updated_at, deleted_at, benefices, id_pays) SELECT gen_random_uuid(), v.* FROM (VALUES ('Gestion commerciale : motivation de l''équipe', 'Formation sur la gestion commerciale et la motivation des équipes pour améliorer la performance et l’engagement.', 5, 250000.00, 'entreprise', '2026-03-05', 30, '2026-01-14 12:37:32', '2026-01-14 12:37:32', NULL, E'--- OBJECTIFS ---\n• Développer des compétences de management commercial\n• Comprendre les leviers de motivation des collaborateurs\n• Mettre en place des techniques pour impliquer et fidéliser l’équipe\n• Optimiser la performance individuelle et collective\n• Renforcer la cohésion et l’engagement commercial\n\n--- OBJECTIFS DÉTAILLÉS ---\nInitier les managers et responsables commerciaux aux techniques de motivation, leur apprendre à impliquer les collaborateurs, optimiser la performance et renforcer la cohésion d’équipe.\n\n--- PRÉREQUIS ---\nExpérience préalable en management ou gestion d’équipe souhaitée.\n\n--- CONTENU ---\nModule 1 : Introduction à la gestion commerciale\nModule 2 : Les principes de motivation et d’engagement\nModule 3 : Techniques pour motiver et fidéliser l’équipe\nModule 4 : Communication et feedback constructif\nModule 5 : Gestion des performances et suivi\nModule 6 : Atelier pratique – Élaboration d’un plan de motivation\n\n--- NIVEAU ---\nTous niveaux\n\n--- PUBLIC ---\nManagers commerciaux, responsables d’équipe, chefs de projet et toute personne impliquée dans la gestion commerciale.\n\n--- MÉTHODES ---\nPrésentations interactives, études de cas, ateliers pratiques, jeux de rôle et simulations.\n\n--- SUPPORTS ---\nManuel du participant, fiches pratiques, modèles de plan de motivation, supports PDF, slides et vidéos pédagogiques.\n\n--- CERTIFICATION ---\nAttestation de participation remise par ISD Groupe', 'ba52f30c-c061-41b8-b0f7-afa6eca6fa76')) AS v(titre, description, duree, prix, categorie, date_debut, places_disponibles, created_at, updated_at, deleted_at, benefices, id_pays) WHERE NOT EXISTS (SELECT 1 FROM formations f WHERE f.titre = v.titre AND f.date_debut = v.date_debut::date);
